          return JSON.stringify({ error: "mark_read requires messageId" });
        }
        await markAsRead(args.messageId);
        return JSON.stringify({ success: true, messageId: args.messageId });
      }
      default:
        return JSON.stringify({ error: "Unknown action" });
    }
  }
};
